class GyroSvgToggleButton extends StatelessWidget {
  const GyroSvgToggleButton({
    super.key,
    required this.value,
    required this.onTap,
    this.size = 36,
  });

  final bool value;
  final VoidCallback onTap;
  final double size;

  @override
  Widget build(BuildContext context) {
    return Semantics(
      button: true,
      label: value ? '陀螺仪开' : '陀螺仪关',
      child: SizedBox(
        width: size,
        height: size,
        child: Material(
          color: Colors.transparent,
          child: InkWell(
            onTap: onTap,
            customBorder: const CircleBorder(),
            child: SvgPicture.string(
              value ? _gyroOnSvg : _gyroOffSvg,
              width: size,
              height: size,
            ),
          ),
        ),
      ),
    );
  }
}
